from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.DEBUG, format='%(asctime)s - %(levelname)s - %(message)s')

class RequestFormatter(logging.Formatter):
    def format(self, record):
        record.request_data = f"Headers: {request.headers}, Body: {request.get_data(as_text=True)}"
        return super().format(record)

# Create a handler for the log file
handler = logging.FileHandler('app.log')
handler.setFormatter(RequestFormatter())

# Add the handler to the root logger
logging.getLogger('').addHandler(handler)

@app.before_request
def log_request_info():
    if request.method == 'POST' or request.method == 'PUT':
        logging.debug(f"Request received: {request.method} {request.url}", extra={'request_data': request.get_data(as_text=True)})
    else:
        logging.debug(f"Request received: {request.method} {request.url}")

@app.after_request
def log_response_info(response):
    logging.debug("Response sent", extra={'response_status': response.status, 'response_data': response.get_data(as_text=True)})
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    logging.error(f"Exception occurred: {e}", exc_info=True)
    return jsonify({'error': str(e)}), 500

@app.route('/login', methods=['POST'])
def login():
    auth = request.authorization
    if not auth or auth.password != 'secret':
        logging.warning("Failed login attempt", extra={'username': auth.username, 'password': auth.password})
        return jsonify({'message': 'Authentication Failed'}), 401

    logging.info(f"User logged in: {auth.username}")
    return jsonify({'message': f'Logged in as {auth.username}'})

if __name__ == '__main__':
    app.run(debug=True)